// tool-calling to research a topic on the web and take structured notes,
// then produce a final summary.
// ---------------------------------------------------------------------------

// --- Configuration --------------------------------------------------------

var modelName = Environment.GetEnvironmentVariable("RESEARCH_AGENT_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// --- Tool instances -------------------------------------------------------

var notebook = new Notebook();
var webSearch = new WebSearchService();

// --- Build the chat client with automatic function invocation -------------

IChatClient client = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- System prompt --------------------------------------------------------

const string SystemPrompt = """
    You are a research agent. The user will give you a topic to research.

    Your workflow:
    1. Break the topic into 2-3 focused search queries.
    2. For each query, call the SearchWeb tool.
    3. As you find useful information, call AddNote to record key facts,
       data points, or quotes along with their source URL.
    4. After gathering enough information, call GetNotes to review everything.
    5. Finally, produce a well-structured summary of your findings using the
       notes you collected. Include source references.

    Be thorough but concise. Prefer facts and data over opinions.
    """;

// --- Main interaction loop ------------------------------------------------

Console.WriteLine("🔬 Research Agent");
Console.WriteLine("Type a topic to research, or 'quit' to exit.\n");

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.WriteLine($"\nResearching: {topic}\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, SystemPrompt),
        new(ChatRole.User, $"Research the following topic and give me a summary: {topic}"),
    };

    // Agentic loop – keep going while the model wants to call tools.
    // UseFunctionInvocation() handles the tool dispatch automatically,
    // so we simply stream until the model produces a final text response.
    bool done = false;
    while (!done)
    {
        var response = await client.GetResponseAsync(messages, chatOptions);

        // Append all response messages to the conversation.
        messages.AddRange(response.Messages);

