/// <summary>
/// A simple web search tool that queries DuckDuckGo's HTML endpoint and
/// extracts result snippets for the AI to consume.
/// </summary>
sealed class WebSearchService
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Searches the web for the given query and returns a list of result snippets with URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query,
        [Description("Max number of results to return (default 5)")] int maxResults = 5)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await Http.GetStringAsync(url);

            var results = ParseDuckDuckGoResults(html, maxResults);

            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            for (int i = 0; i < results.Count; i++)
            {
                var r = results[i];
                sb.AppendLine($"[{i + 1}] {r.Title}");
                sb.AppendLine($"    URL: {r.Url}");
                sb.AppendLine($"    {r.Snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoResults(string html, int max)
    {
        var results = new List<SearchResult>();

        // Simple extraction of result blocks from DuckDuckGo HTML.
        var resultMarker = "class=\"result__a\"";
        var pos = 0;

        while (results.Count < max && (pos = html.IndexOf(resultMarker, pos, StringComparison.Ordinal)) >= 0)
        {
            // Extract href
            var hrefStart = html.LastIndexOf("href=\"", pos, Math.Min(pos, 200), StringComparison.Ordinal);
            var link = "";
            if (hrefStart >= 0)
            {
                hrefStart += 6;
                var hrefEnd = html.IndexOf('"', hrefStart);
                if (hrefEnd > hrefStart)
                    link = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
            }

            // Extract title (text inside the <a> tag)
            var tagClose = html.IndexOf('>', pos);
            var titleEnd = tagClose > 0 ? html.IndexOf("</a>", tagClose, StringComparison.Ordinal) : -1;
            var title = tagClose > 0 && titleEnd > tagClose
                ? StripHtml(html[(tagClose + 1)..titleEnd])
                : "(no title)";

            // Extract snippet
            var snippetMarker = "class=\"result__snippet\"";
            var snippetPos = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal);
            var snippet = "";
            if (snippetPos > 0 && snippetPos < pos + 3000)
            {
                var sTagClose = html.IndexOf('>', snippetPos);
                var sEnd = sTagClose > 0
                    ? html.IndexOf("</", sTagClose, StringComparison.Ordinal)
                    : -1;
                if (sTagClose > 0 && sEnd > sTagClose)
                    snippet = StripHtml(html[(sTagClose + 1)..sEnd]).Trim();
            }

            if (!string.IsNullOrWhiteSpace(title))
                results.Add(new SearchResult(title.Trim(), link.Trim(), snippet));

            pos = Math.Max(pos + 1, titleEnd > 0 ? titleEnd : pos + 1);
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder(html.Length);
        bool inside = false;
        foreach (var ch in html)
        {
            if (ch == '<') { inside = true; continue; }
            if (ch == '>') { inside = false; continue; }
            if (!inside) sb.Append(ch);
        }
        return WebUtility.HtmlDecode(sb.ToString());
    }

    record SearchResult(string Title, string Url, string Snippet);
}

/// <summary>
/// A note-taking tool that stores research notes in memory.
/// </summary>
sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note. Use this to record key facts, data points, or quotes found during research.")]
    public string AddNote(
        [Description("The content of the note")] string content,
        [Description("The source URL where this information was found")] string source,
        [Description("A short tag/category for the note (e.g. 'statistics', 'definition', 'quote')")] string tag = "general")
    {
        _notes.Add(new Note(content, source, tag));
        Console.WriteLine($"  📝 Note added [{tag}]: {Truncate(content, 60)}");
        return $"Note #{_notes.Count} saved under [{tag}].";
    }

    [Description("Retrieves all notes taken so far, organized by tag.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");

        var sb = new StringBuilder();
        var grouped = _notes.GroupBy(n => n.Tag);
        foreach (var group in grouped)
        {
            sb.AppendLine($"## [{group.Key}]");
            foreach (var note in group)
            {
                sb.AppendLine($"- {note.Content}");
                sb.AppendLine($"  Source: {note.Source}");
            }
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static string Truncate(string s, int max) =>
        s.Length <= max ? s : s[..(max - 3)] + "...";

    record Note(string Content, string Source, string Tag);
}

